vec![
    t!("carch-1", "computer", "architecture", "冯诺依曼架构", "经典计算机体系结构，包含运算器、控制器、存储器、输入和输出设备五大部分，指令和数据共享总线。"),
    t!("carch-2", "computer", "architecture", "哈佛架构", "指令存储和数据存储分离的总线架构，允许同时取指和存取数据，DSP和微控制器常用。"),
    t!("carch-3", "computer", "architecture", "CPU / 中央处理器", "计算机的核心运算和控制单元，执行指令、处理数据，包含ALU、控制单元和寄存器组。"),
    t!("carch-4", "computer", "architecture", "指令集架构 / ISA", "处理器与软件之间的抽象接口，定义了指令格式、寄存器、寻址模式和数据类型，x86和ARM为代表。"),
    t!("carch-5", "computer", "architecture", "RISC / 精简指令集", "简化指令集的处理器设计哲学，固定指令长度、加载存储架构，ARM和RISC-V为代表。"),
    t!("carch-6", "computer", "architecture", "CISC / 复杂指令集", "具有丰富复杂指令的处理器设计，单条指令可完成多步操作，x86-64为代表。"),
    t!("carch-7", "computer", "architecture", "ARM架构", "基于RISC的处理器架构，低功耗高性能，主导移动和嵌入式市场，Apple Silicon转向ARM。"),
    t!("carch-8", "computer", "architecture", "x86-64 / AMD64", "AMD扩展x86的64位指令集，保持向后兼容，PC和服务器主流架构。"),
    t!("carch-9", "computer", "architecture", "RISC-V", "伯克利开发的开放指令集架构，模块化设计，免许可证，IoT和AI加速器领域快速增长。"),
    t!("carch-10", "computer", "architecture", "流水线 / Pipeline", "将指令执行分解为多个阶段并行处理，提升吞吐率但引入数据和控制冒险。"),
    t!("carch-11", "computer", "architecture", "超标量 / Superscalar", "每个时钟周期发射和执行多条指令的处理器架构，需要复杂调度逻辑。"),
    t!("carch-12", "computer", "architecture", "乱序执行 / Out-of-Order", "处理器不按程序顺序执行指令以减少流水线停顿，通过重排序缓冲区和保留站实现。"),
    t!("carch-13", "computer", "architecture", "分支预测 / Branch Prediction", "处理器猜测分支指令走向并预取指令，减少流水线刷新损失。"),
    t!("carch-14", "computer", "architecture", "推测执行 / Speculative Execution", "在分支结果确认前预先执行指令，Spectre和Meltdown漏洞即利用这一特性。"),
    t!("carch-15", "computer", "architecture", "SIMD / 单指令多数据", "一条指令同时操作多个数据元素的并行计算技术，MMX/SSE/AVX/NEON为其实现。"),
    t!("carch-16", "computer", "architecture", "GPU架构", "专为大规模并行计算设计的众核处理器，SIMT执行模型，NVIDIA CUDA和AMD ROCm为编程平台。"),
    t!("carch-17", "computer", "architecture", "TPU / 张量处理单元", "Google设计的AI专用加速器，针对矩阵乘法和卷积优化，内置脉动阵列。"),
    t!("carch-18", "computer", "architecture", "FPGA / 现场可编程门阵列", "可重配置的硬件加速器，通过硬件描述语言定义逻辑电路，灵活性与效率兼顾。"),
    t!("carch-19", "computer", "architecture", "ASIC / 专用集成电路", "为特定应用定制设计的芯片，性能和能效最优但开发成本高、灵活性低。"),
    t!("carch-20", "computer", "architecture", "缓存层次 / Cache Hierarchy", "L1→L2→L3三级缓存结构，利用局部性原理缩小处理器与主存之间的速度差距。"),
    t!("carch-21", "computer", "architecture", "缓存一致性 / Cache Coherence", "多核系统中各核缓存数据保持一致，MESI/MOESI协议为常见实现。"),
    t!("carch-22", "computer", "architecture", "存储层次 / Memory Hierarchy", "从寄存器到磁带的速度-容量-成本递阶结构，越靠近处理器越快越贵越小。"),
    t!("carch-23", "computer", "architecture", "TLB / 快表", "在CPU内缓存虚拟地址到物理地址的转换，加速页表查找减少内存访问。"),
    t!("carch-24", "computer", "architecture", "NUMA / 非统一内存访问", "多处理器架构中访问本地内存快于远端内存，需要感知拓扑的调度和分配。"),
    t!("carch-25", "computer", "architecture", "DMA / 直接内存访问", "外设直接与内存交换数据而不经过CPU，释放CPU用于计算任务。"),
    t!("carch-26", "computer", "architecture", "中断 / Interrupt", "硬件或软件信号暂停当前程序转而执行中断服务程序，是操作系统响应事件的基石。"),
    t!("carch-27", "computer", "architecture", "微架构 / Microarchitecture", "ISA的具体硬件实现，包括流水线深度、执行单元数量和缓存设计。"),
    t!("carch-28", "computer", "architecture", "多核 / Multi-core", "在单一芯片上集成多个处理器核，共享或不共享缓存，提升并行处理能力。"),
    t!("carch-29", "computer", "architecture", "同时多线程 / SMT / Hyper-Threading", "单核同时执行多个线程，利用超标量资源的空闲执行单元提升吞吐。"),
    t!("carch-30", "computer", "architecture", "内存控制器", "管理处理器和系统内存之间数据流，集成到CPU内降低延迟。"),
    t!("carch-31", "computer", "architecture", "PCIe / 高速外设互连", "点对点串行总线标准，连接GPU、NVMe SSD和网卡等高速外设。"),
    t!("carch-32", "computer", "architecture", "CXL / Compute Express Link", "基于PCIe的开放互连标准，支持缓存一致性共享内存和资源池化。"),
    t!("carch-33", "computer", "architecture", "片上网络 / NoC", "多核芯片内部互连架构，通过路由器网络替代传统总线和交叉开关。"),
    t!("carch-34", "computer", "architecture", "芯片互联 / Chiplet", "将大芯片拆分为多个小芯片通过高速接口互联，降低制造成本提升良率。"),
    t!("carch-35", "computer", "architecture", "UCIe / 通用芯粒互连", "Intel主导的开放芯粒互连标准，推动多厂商Chiplet生态互操作。"),
    t!("carch-36", "computer", "architecture", "异构计算 / Heterogeneous Computing", "整合不同类型处理器（CPU+GPU+FPGA+ASIC）各取所长的计算架构。"),
    t!("carch-37", "computer", "architecture", "存内计算 / Processing-in-Memory", "在内存芯片内部集成计算单元，突破冯诺依曼瓶颈减少数据搬运。"),
    t!("carch-38", "computer", "architecture", "量子计算架构", "基于量子比特叠加和纠缠的计算模型，需极低温运行，当前处于含噪中等规模量子阶段。"),
    t!("carch-39", "computer", "architecture", "神经形态芯片", "模仿人脑神经元和突触的计算架构，稀疏脉冲驱动、事件触发，功耗极低。"),
    t!("carch-40", "computer", "architecture", "晶圆级芯片 / Wafer-Scale", "在整片硅晶圆上制造超大规模芯片，Cerebras的WSE-3为代表。"),
    t!("carch-41", "computer", "architecture", "3D堆叠 / 3D Stacking", "通过硅通孔垂直堆叠芯片层，提升带宽降低功耗，HBM内存为代表。"),
    t!("carch-42", "computer", "architecture", "功耗管理 / Power Management", "DVFS动态调频调压、时钟门控和电源门控等技术平衡性能与功耗。"),
    t!("carch-43", "computer", "architecture", "暗硅 / Dark Silicon", "因功耗约束无法同时激活所有晶体管的芯片面积，多核时代的设计挑战。"),
    t!("carch-44", "computer", "architecture", "可靠性设计 / Dependable Design", "通过ECC纠错码、冗余和看门狗提高系统的故障容错和数据完整性。"),
    t!("carch-45", "computer", "architecture", "安全飞地 / Secure Enclave", "处理器内隔离执行的可信执行环境，Intel SGX和ARM TrustZone为代表。"),
    t!("carch-46", "computer", "architecture", "硬件虚拟化", "处理器提供虚拟化扩展（Intel VT-x/AMD-V），高效运行虚拟机监控器。"),
    t!("carch-47", "computer", "architecture", "性能计数器 / Performance Counter", "处理器内置的事件监控寄存器，记录缓存未命中、分支失误等微架构事件。"),
    t!("carch-48", "computer", "architecture", "Roofline模型", "评估计算平台性能上限的模型，结合计算能力和内存带宽分析应用瓶颈。"),
    t!("carch-49", "computer", "architecture", "Amdahl定律", "系统优化加速比受限于不可并行部分的比例，是并行计算收益的理论上限。"),
    t!("carch-50", "computer", "architecture", "摩尔定律", "集成电路上可容纳的晶体管数目约每两年翻一番的观察规律，物理极限渐近。"),
]
